// ===== Étape 1 : liste des decks à rafraîchir (depuis tcgp_data.json) =====
const t = $('Veille tcgp').first().json;
const seen = {};
const decks = [];
for (const d of [...(t.topUsage||[]), ...(t.topWinrate||[])]) {
  if (!d.limitless || seen[d.name]) continue;
  seen[d.name] = true;
  decks.push({ json: { name: d.name, slug: d.limitless } });
}
if (!decks.length) throw new Error('Aucun deck avec slug Limitless dans tcgp_data.json');
return decks;

// ===== Étape 2 (par deck) : trouver la meilleure decklist de la semaine =====
const html = String($json.data || '');
const meta = $('Decks à rafraîchir').item.json;
const strip = s => String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
let dlUrl = null, player = '', place = '', score = '';
for (const tr of html.match(/<tr[\s\S]*?<\/tr>/g) || []) {
  const a = tr.match(/<a[^>]*href="(\/tournament\/[^"]*\/decklist)"[^>]*>([\s\S]*?)<\/a>/);
  if (!a) continue;
  dlUrl = 'https://play.limitlesstcg.com' + a[1];
  player = strip(a[2]);
  const cells = [...tr.matchAll(/<td[^>]*>([\s\S]*?)<\/td>/g)].map(m=>strip(m[1]));
  place = (cells.find(c=>/^\d+(st|nd|rd|th) of \d+/.test(c))||'').split(' of ')[0];
  score = cells.find(c=>/^\d+\s*-\s*\d+\s*-\s*\d+$/.test(c))||'';
  break;
}
if (!dlUrl) return { json: { name: meta.name, skip: true } };
return { json: { name: meta.name, dlUrl, player, place, score: score.replace(/\s/g,'') } };

// ===== Étape 3 (par deck) : parser la decklist (20 cartes) =====
const meta = $('Trouver la liste').item.json;
if (meta.skip) return { json: { name: meta.name, skip: true } };
const html = String($json.data || '');
const strip = s => String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const OVERRIDES = {'teal mask ogerpon':'ogerpon','castform sunny form':'castform-sunny','oricorio':'oricorio-pom-pom','chien-pao':'chien-pao','iron valiant':'iron-valiant','iron boulder':'iron-boulder','flutter mane':'flutter-mane','great tusk':'great-tusk'};
function spriteSlug(name){
  let n = String(name).replace(/\s+ex$/i,'').trim();
  const mega = /^Mega\s+/i.test(n); if(mega) n = n.replace(/^Mega\s+/i,'');
  const low = n.toLowerCase();
  for (const k in OVERRIDES) if (low.startsWith(k)) return OVERRIDES[k] + (mega?'-mega':'');
  return low.replace(/['’.]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'') + (mega?'-mega':'');
}
const sections = {};
for (const sec of html.match(/<div class="cards">[\s\S]*?<\/div><\/div>|<div class="cards">[\s\S]*?(?=<div class="cards">|<\/div><\/div>)/g) || html.split('<div class="cards">').slice(1).map(s=>'<div class="cards">'+s)) {
  const head = (sec.match(/<div class="heading">([\s\S]*?)<\/div>/)||[])[1];
  if (!head) continue;
  const cards = [...sec.matchAll(/<a[^>]*>\s*(\d+)\s+([^<(]+?)(?:\s*\(([^)]+)\))?\s*<\/a>/g)]
    .map(m=>({ q:+m[1], n:strip(m[2]), set:m[3]||undefined }));
  if (/Pok/i.test(head)) sections.pokemon = cards.map(c=>({q:c.q,n:c.n,s:spriteSlug(c.n)}));
  else if (/Trainer/i.test(head)) sections.trainers = cards.map(c=>({q:c.q,n:c.n}));
}
if (!sections.pokemon || !sections.pokemon.length) return { json: { name: meta.name, skip: true } };
return { json: { name: meta.name, cards: { pokemon: sections.pokemon, trainers: sections.trainers||[], energy: [] },
  listBy: meta.player + (meta.place?' ('+meta.place+(meta.score?', '+meta.score:'')+')':'') } };

// ===== Étape 4 : fusionner dans tcgp_data.json + commit =====
const t = $('Veille tcgp').first().json;
const fresh = $input.all().map(i=>i.json).filter(d=>!d.skip && d.cards);
if (!fresh.length) throw new Error('Aucune decklist récupérée — rien à commiter');
const byName = {}; fresh.forEach(d=>byName[d.name]=d);
let updated = 0;
for (const list of [t.topUsage, t.topWinrate, t.topDecks]) {
  if (!Array.isArray(list)) continue;
  for (const d of list) {
    const f = byName[d.name];
    if (f) { d.cards = f.cards; d.listBy = f.listBy; updated++; }
  }
}
t.updatedAt = new Date().toISOString();
return [{ json: {
  content: JSON.stringify(t, null, 2),
  msg: 'bot(decklists) ' + new Date().toLocaleDateString('fr-FR') + ' : ' + fresh.length + ' decklists rafraîchies (' + fresh.map(d=>d.name.split(' ')[0]).slice(0,4).join(', ') + '…)'
}}];
